async function handleGetCustomer(request, env, corsHeaders) {
  const url = new URL(request.url);
  const customerId = url.searchParams.get('id');

  if (!customerId) {
    return jsonResponse(400, { error: 'Customer id is required as query parameter' }, corsHeaders);
  }

  if (!customerId.startsWith('cus_')) {
    return jsonResponse(400, { error: 'Invalid customer ID format' }, corsHeaders);
  }

  const result = await stripeRequest(`/v1/customers/${encodeURIComponent(customerId)}`, 'GET', null, env);

  if (!result.ok) {
    return jsonResponse(mapStripeError(result.data), {
      error: 'Failed to retrieve customer',
      details: result.data?.error || result.data,
    }, corsHeaders);
  }

  return jsonResponse(200, {
    success: true,
    customer: {
      id: result.data.id,
      email: result.data.email,
      name: result.data.name,
      phone: result.data.phone,
      created: result.data.created,
      metadata: result.data.metadata,
    },
  }, corsHeaders);
}

